"use client";

import { motion } from "framer-motion";

type MarqueeItem = {
  title: string;
  icon: React.ReactNode;
};

type MarqueeProps = {
  items: MarqueeItem[];
  direction?: "left" | "right";
  duration?: number;
};

function MarqueeRow({
  items,
  direction = "left",
  duration = 20,
}: MarqueeProps) {
  const doubled = [...items, ...items];

  return (
    <div className="relative max-w-5xl overflow-hidden  py-4">
      <div className="absolute top-0 left-0 bottom-0 w-16 bg-gradient-to-r from-[#000000] to-transparent pointer-events-none z-10"></div>
      <motion.div
        className="flex w-max gap-10 whitespace-nowrap"
        animate={{
          x: direction === "left" ? ["0%", "-50%"] : ["-50%", "0%"],
        }}
        transition={{
          duration,
          ease: "linear",
          repeat: Infinity,
        }}
      >
        {doubled.map((item, i) => (
          <div
            key={`${item.title}-${i}`}
            className="flex shrink-0 items-center gap-3"
          >
            <span>{item.icon}</span>
        
            <span className="font-mono text-xs uppercase tracking-[0.3em] text-zinc-400">
              {item.title}
            </span>
        
            <span className="text-[8px] text-[#38b6ff] ml-5">•</span>
          </div>
        ))}
      </motion.div>
      <div className="absolute top-0 right-0 bottom-0 w-16 bg-gradient-to-l from-[#000000] to-transparent pointer-events-none z-10"></div>
    </div>
  );
}

